import React, { useState, useEffect } from 'react';
import avatar from './avatar.gif';

function Mascotte({ messages, position = 'left' }) {
  const [texteAffiche, setTexteAffiche] = useState('');
  const [indexMessage, setIndexMessage] = useState(0);
  const [indexChar, setIndexChar] = useState(0);
  const [visible, setVisible] = useState(true);

  // Animation de frappe
  useEffect(() => {
    if (indexChar < messages[indexMessage].length) {
      const timer = setTimeout(() => {
        setTexteAffiche(prev => prev + messages[indexMessage][indexChar]);
        setIndexChar(prev => prev + 1);
      }, 40);
      return () => clearTimeout(timer);
    } else {
      // Attendre 3 secondes puis passer au message suivant
      const timer = setTimeout(() => {
        setVisible(false);
        setTimeout(() => {
          setTexteAffiche('');
          setIndexChar(0);
          setIndexMessage(prev => (prev + 1) % messages.length);
          setVisible(true);
        }, 500);
      }, 3000);
      return () => clearTimeout(timer);
    }
  }, [indexChar, indexMessage, messages]);

  const isLeft = position === 'left';

  return (
    <div style={{
      display: 'flex',
      alignItems: 'flex-end',
      gap: '12px',
      flexDirection: isLeft ? 'row' : 'row-reverse',
      opacity: visible ? 1 : 0,
      transition: 'opacity 0.4s ease',
      margin: '30px 0'
    }}>
      {/* PERSONNAGE */}
      <div style={{
        flexShrink: 0,
        width: '70px', height: '70px',
        borderRadius: '50%',
        border: '3px solid #ffd700',
        overflow: 'hidden',
        boxShadow: '0 0 20px rgba(255,215,0,0.4)',
        animation: 'float 3s ease-in-out infinite'
      }}>
        <img src={avatar} alt="mascotte" style={{ width: '100%', height: '100%', objectFit: 'cover' }} />
      </div>

      {/* BULLE DE DIALOGUE */}
      <div style={{
        background: 'rgba(0,20,0,0.9)',
        border: '1px solid #ffd700',
        borderRadius: isLeft ? '20px 20px 20px 0' : '20px 20px 0 20px',
        padding: '14px 18px',
        maxWidth: '280px',
        position: 'relative',
        boxShadow: '0 0 20px rgba(255,215,0,0.15)'
      }}>
        <p style={{
          color: '#e8e8e8',
          fontFamily: "'Rajdhani', sans-serif",
          fontSize: '14px',
          lineHeight: 1.6,
          margin: 0,
          minHeight: '20px'
        }}>
          {texteAffiche}
          <span style={{
            display: 'inline-block',
            width: '2px', height: '14px',
            background: '#00aa00',
            marginLeft: '2px',
            animation: 'blink 0.7s infinite'
          }} />
        </p>
      </div>

      <style>{`
        @keyframes float {
          0%, 100% { transform: translateY(0px); }
          50% { transform: translateY(-8px); }
        }
        @keyframes blink {
          0%, 100% { opacity: 1; }
          50% { opacity: 0; }
        }
      `}</style>
    </div>
  );
}

export default Mascotte;
